B.aCG=new A.iY(B.jJ,"Is this data official and accurate?","Yes. All data in UAE Stats comes directly from the Federal Competitiveness and Statistics Centre (FCSC) \u2014 the official national statistical authority of the UAE. Data is sourced from ministries, civil registration systems, and approved surveys, and follows international SDMX standards used by the World Bank and IMF.","\u0647\u0644 \u0647\u0630\u0647 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0631\u0633\u0645\u064a\u0629 \u0648\u062f\u0642\u064a\u0642\u0629\u061f","\u0646\u0639\u0645. \u062c\u0645\u064a\u0639 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u062a\u0623\u062a\u064a \u0645\u0628\u0627\u0634\u0631\u0629 \u0645\u0646 \u0627\u0644\u0645\u0631\u0643\u0632 \u0627\u0644\u0627\u062a\u062d\u0627\u062f\u064a \u0644\u0644\u062a\u0646\u0627\u0641\u0633\u064a\u0629 \u0648\u0627\u0644\u0625\u062d\u0635\u0627\u0621 \u2014 \u0627\u0644\u062c\u0647\u0629 \u0627\u0644\u0625\u062d\u0635\u0627\u0626\u064a\u0629 \u0627\u0644\u0631\u0633\u0645\u064a\u0629 \u0641\u064a \u0627\u0644\u062f\u0648\u0644\u0629. \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0645\u0633\u062a\u0642\u0627\u0629 \u0645\u0646 \u0627\u0644\u0648\u0632\u0627\u0631\u0627\u062a \u0648\u0623\u0646\u0638\u0645\u0629 \u0627\u0644\u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u0645\u062f\u0646\u064a \u0648\u0627\u0644\u0645\u0633\u0648\u062d \u0627\u0644\u0645\u0639\u062a\u0645\u062f\u0629 \u0648\u062a\u062a\u0628\u0639 \u0645\u0639\u0627\u064a\u064a\u0631 SDMX \u0627\u0644\u062f\u0648\u0644\u064a\u0629.")
B.aCP=new A.iY(B.jJ,"How current is the data?","Data is updated based on the publication cycle of each indicator. For example, CPI (inflation) is updated monthly, while population estimates are updated annually. The date shown on each indicator tells you when it was last released.","\u0645\u0627 \u0645\u062f\u0649 \u062d\u062f\u0627\u062b\u0629 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a\u061f","\u064a\u062a\u0645 \u062a\u062d\u062f\u064a\u062b \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0648\u0641\u0642\u0627\u064b \u0644\u062f\u0648\u0631\u0629 \u0646\u0634\u0631 \u0643\u0644 \u0645\u0624\u0634\u0631. \u0639\u0644\u0649 \u0633\u0628\u064a\u0644 \u0627\u0644\u0645\u062b\u0627\u0644\u060c \u064a\u064f\u062d\u062f\u0651\u062b \u0645\u0624\u0634\u0631 \u0623\u0633\u0639\u0627\u0631 \u0627\u0644\u0645\u0633\u062a\u0647\u0644\u0643 \u0634\u0647\u0631\u064a\u0627\u064b \u0628\u064a\u0646\u0645\u0627 \u062a\u064f\u062d\u062f\u0651\u062b \u062a\u0642\u062f\u064a\u0631\u0627\u062a \u0627\u0644\u0633\u0643\u0627\u0646 \u0633\u0646\u0648\u064a\u0627\u064b.")
B.aCO=new A.iY(B.jJ,"What does the YoY percentage mean?","YoY stands for Year-on-Year. It compares this year's value to the same period last year, expressed as a percentage change. A positive number means growth; a negative number means a decrease.","\u0645\u0627\u0630\u0627 \u062a\u0639\u0646\u064a \u0627\u0644\u0646\u0633\u0628\u0629 \u0627\u0644\u0645\u0626\u0648\u064a\u0629 \u0644\u0644\u062a\u063a\u064a\u0631 \u0627\u0644\u0633\u0646\u0648\u064a\u061f","\u0627\u0644\u062a\u063a\u064a\u0631 \u0627\u0644\u0633\u0646\u0648\u064a (YoY) \u064a\u0642\u0627\u0631\u0646 \u0642\u064a\u0645\u0629 \u0647\u0630\u0627 \u0627\u0644\u0639\u0627\u0645 \u0628\u0646\u0641\u0633 \u0627\u0644\u0641\u062a\u0631\u0629 \u0645\u0646 \u0627\u0644\u0639\u0627\u0645 \u0627\u0644\u0645\u0627\u0636\u064a \u0643\u0646\u0633\u0628\u0629 \u0645\u0626\u0648\u064a\u0629. \u0627\u0644\u0631\u0642\u0645 \u0627\u0644\u0645\u0648\u062c\u0628 \u064a\u0639\u0646\u064a \u0646\u0645\u0648\u0627\u064b \u0648\u0627\u0644\u0633\u0627\u0644\u0628 \u064a\u0639\u0646\u064a \u0627\u0646\u062e\u0641\u0627\u0636\u0627\u064b.")
B.jK=new A.oP(1,"app")
B.aCL=new A.iY(B.jK,"How do I switch between English and Arabic?","Tap the language toggle (EN | AR) in the top-right of the app bar. The app switches immediately, including text direction.","\u0643\u064a\u0641 \u0623\u0628\u062f\u0651\u0644 \u0628\u064a\u0646 \u0627\u0644\u0639\u0631\u0628\u064a\u0629 \u0648\u0627\u0644\u0625\u0646\u062c\u0644\u064a\u0632\u064a\u0629\u061f","\u0627\u0636\u063a\u0637 \u0639\u0644\u0649 \u0632\u0631 \u062a\u0628\u062f\u064a\u0644 \u0627\u0644\u0644\u063a\u0629 (EN | AR) \u0623\u0639\u0644\u0649 \u064a\u0645\u064a\u0646 \u0634\u0631\u064a\u0637 \u0627\u0644\u062a\u0637\u0628\u064a\u0642. \u0633\u064a\u062a\u062d\u0648\u0644 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0641\u0648\u0631\u0627\u064b \u0628\u0645\u0627 \u0641\u064a \u0630\u0644\u0643 \u0627\u062a\u062c\u0627\u0647 \u0627\u0644\u0646\u0635.")
B.aCK=new A.iY(B.jK,"Can I use the app without internet?","The app works without an internet connection by showing the most recently saved data. Connect to the internet to see the most current figures.","\u0647\u0644 \u064a\u0645\u0643\u0646 \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0628\u062f\u0648\u0646 \u0625\u0646\u062a\u0631\u0646\u062a\u061f","\u064a\u0639\u0645\u0644 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0628\u062f\u0648\u0646 \u0627\u062a\u0635\u0627\u0644 \u0628\u0627\u0644\u0625\u0646\u062a\u0631\u0646\u062a \u0645\u0646 \u062e\u0644\u0627\u0644 \u0639\u0631\u0636 \u0622\u062e\u0631 \u0628\u064a\u0627\u0646\u0627\u062a \u0645\u062d\u0641\u0648\u0638\u0629. \u0627\u062a\u0635\u0644 \u0628\u0627\u0644\u0625\u0646\u062a\u0631\u0646\u062a \u0644\u0631\u0624\u064a\u0629 \u0623\u062d\u062f\u062b \u0627\u0644\u0623\u0631\u0642\u0627\u0645.")
B.aCI=new A.iY(B.jK,"How do I save an indicator to view later?","Tap the Bookmark icon on any indicator detail screen. Saved indicators appear in the Bookmarks section, accessible from the side menu.","\u0643\u064a\u0641 \u0623\u062d\u0641\u0638 \u0645\u0624\u0634\u0631\u0627\u064b \u0644\u0623\u0637\u0651\u0644\u0639 \u0639\u0644\u064a\u0647 \u0644\u0627\u062d\u0642\u0627\u064b\u061f","\u0627\u0636\u063a\u0637 \u0639\u0644\u0649 \u0623\u064a\u0642\u0648\u0646\u0629 \u0627\u0644\u0625\u0634\u0627\u0631\u0629 \u0627\u0644\u0645\u0631\u062c\u0639\u064a\u0629 \u0641\u064a \u0623\u064a \u0634\u0627\u0634\u0629 \u062a\u0641\u0627\u0635\u064a\u0644 \u0645\u0624\u0634\u0631. \u062a\u0638\u0647\u0631 \u0627\u0644\u0645\u0624\u0634\u0631\u0627\u062a \u0627\u0644\u0645\u062d\u0641\u0648\u0638\u0629 \u0641\u064a \u0642\u0633\u0645 \u0627\u0644\u0625\u0634\u0627\u0631\u0627\u062a \u0627\u0644\u0645\u0631\u062c\u0639\u064a\u0629 \u0645\u0646 \u0627\u0644\u0642\u0627\u0626\u0645\u0629 \u0627\u0644\u062c\u0627\u0646\u0628\u064a\u0629.")
B.ny=new A.oP(2,"fcsc")
B.aCH=new A.iY(B.ny,"What is FCSC?","The Federal Competitiveness and Statistics Centre (FCSC) is the official national statistical authority of the United Arab Emirates, responsible for producing, disseminating, and safeguarding official UAE statistics across all government sectors.","\u0645\u0627 \u0647\u0648 \u0627\u0644\u0645\u0631\u0643\u0632 \u0627\u0644\u0627\u062a\u062d\u0627\u062f\u064a \u0644\u0644\u062a\u0646\u0627\u0641\u0633\u064a\u0629 \u0648\u0627\u0644\u0625\u062d\u0635\u0627\u0621\u061f","\u0627\u0644\u0645\u0631\u0643\u0632 \u0627\u0644\u0627\u062a\u062d\u0627\u062f\u064a \u0644\u0644\u062a\u0646\u0627\u0641\u0633\u064a\u0629 \u0648\u0627\u0644\u0625\u062d\u0635\u0627\u0621 \u0647\u0648 \u0627\u0644\u062c\u0647\u0629 \u0627\u0644\u0625\u062d\u0635\u0627\u0626\u064a\u0629 \u0627\u0644\u0631\u0633\u0645\u064a\u0629 \u0644\u062f\u0648\u0644\u0629 \u0627\u0644\u0625\u0645\u0627\u0631\u0627\u062a\u060c \u0648\u0647\u0648 \u0645\u0633\u0624\u0648\u0644 \u0639\u0646 \u0625\u0646\u062a\u0627\u062c \u0648\u0646\u0634\u0631 \u0648\u062d\u0645\u0627\u064a\u0629 \u0627\u0644\u0625\u062d\u0635\u0627\u0621\u0627\u062a \u0627\u0644\u0631\u0633\u0645\u064a\u0629 \u0639\u0628\u0631 \u062c\u0645\u064a\u0639 \u0627\u0644\u0642\u0637\u0627\u0639\u0627\u062a \u0627\u0644\u062d\u0643\u0648\u0645\u064a\u0629.")
B.aCJ=new A.iY(B.ny,"How can I contact FCSC?","You can reach FCSC via email at info@fcsc.gov.ae or visit uaestat.fcsc.gov.ae for the full data portal and contact information.","\u0643\u064a\u0641 \u064a\u0645\u0643\u0646\u0646\u064a \u0627\u0644\u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u0627\u0644\u0645\u0631\u0643\u0632\u061f","\u064a\u0645\u0643\u0646\u0643 \u0627\u0644\u062a\u0648\u0627\u0635\u0644 \u0645\u0639 \u0627\u0644\u0645\u0631\u0643\u0632 \u0639\u0628\u0631 \u0627\u0644\u0628\u0631\u064a\u062f \u0627\u0644\u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a info@fcsc.gov.ae \u0623\u0648 \u0632\u064a\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0642\u0639 uaestat.fcsc.gov.ae.")
B.nz=new A.oP(3,"tech")
B.aCN=new A.iY(B.nz,"Where does the app get its data from?","UAE Stats retrieves data directly from the FCSC public SDMX API \u2014 the same data source used by international organisations like the World Bank and IMF.","\u0645\u0646 \u0623\u064a\u0646 \u064a\u062d\u0635\u0644 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0639\u0644\u0649 \u0628\u064a\u0627\u0646\u0627\u062a\u0647\u061f","\u064a\u0633\u062a\u0631\u062c\u0639 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0645\u0628\u0627\u0634\u0631\u0629 \u0645\u0646 \u0648\u0627\u062c\u0647\u0629 \u0628\u0631\u0645\u062c\u0629 \u062a\u0637\u0628\u064a\u0642\u0627\u062a SDMX \u0627\u0644\u0639\u0627\u0645\u0629 \u0644\u0644\u0645\u0631\u0643\u0632 \u2014 \u0646\u0641\u0633 \u0645\u0635\u062f\u0631 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u0630\u064a \u062a\u0633\u062a\u062e\u062f\u0645\u0647 \u0627\u0644\u0645\u0646\u0638\u0645\u0627\u062a \u0627\u0644\u062f\u0648\u0644\u064a\u0629.")
B.aCM=new A.iY(B.nz,"Is my data private? Does the app track me?","UAE Stats does not require login or registration and does not collect personally identifiable information. Anonymous usage data may be collected to improve the app, consistent with UAE Government data protection policies.","\u0647\u0644 \u0628\u064a\u0627\u0646\u0627\u062a\u064a \u062e\u0627\u0635\u0629\u061f \u0647\u0644 \u064a\u062a\u062a\u0628\u0639\u0646\u064a \u0627\u0644\u062a\u0637\u0628\u064a\u0642\u061f","\u0644\u0627 \u064a\u062a\u0637\u0644\u0628 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u062a\u0633\u062c\u064a\u0644 \u062f\u062e\u0648\u0644 \u0648\u0644\u0627 \u064a\u062c\u0645\u0639 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u062a\u0639\u0631\u064a\u0641 \u0634\u062e\u0635\u064a\u0629. \u0642\u062f \u062a\u064f\u062c\u0645\u0639 \u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0645\u062c\u0647\u0648\u0644\u0629 \u0644\u062a\u062d\u0633\u064a\u0646 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0648\u0641\u0642\u0627\u064b \u0644\u0633\u064a\u0627\u0633\u0627\u062a \u062d\u0645\u0627\u064a\u0629 \u0627\u0644\u0628\u064a\u0627\u0646\u0627\u062a \u0627\u0644\u062d\u0643\u0648\u0645\u064a\u0629.")
